const seed = { ...$json };
const issueKey = String(seed.issueKey || '').trim().toUpperCase();
if (!/^(SIS|REC)-\d+$/.test(issueKey)) throw new Error(`issueKey inválido: ${issueKey || '(vacío)'}`);
for (const required of ['jiraBaseUrl', 'jiraApiVersion']) {
  if (!String(seed[required] || seed.context?.[required] || '').trim()) throw new Error(`Falta ${required} para ${issueKey}`);
}
const context = { ...(seed.context || {}), ...seed };
return { json: { ...seed, issueKey, jiraBaseUrl: context.jiraBaseUrl, jiraApiVersion: context.jiraApiVersion, jiraPageSize: Math.min(Math.max(Number(context.jiraPageSize || 100),1),100) } };

const rows = $input.all().map((item) => item.json).filter((row) => row.issueKey);
const byKey = new Map();
for (const row of rows) {
  if (!byKey.has(row.issueKey)) byKey.set(row.issueKey, []);
  byKey.get(row.issueKey).push(row);
}
function allText(value, out = []) {
  if (value == null) return out;
  if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') { out.push(String(value)); return out; }
  if (Array.isArray(value)) { value.forEach((v) => allText(v, out)); return out; }
  if (typeof value === 'object') Object.values(value).forEach((v) => allText(v, out));
  return out;
}
function refs(value, prefix) {
  const r = new RegExp(`\\b${prefix}[\\s_-]*(\\d+)\\b`, 'gi'); const keys = new Set();
  for (const text of allText(value)) for (const m of text.matchAll(r)) keys.add(`${prefix}-${m[1]}`);
  return [...keys];
}
function pageItems(pages, candidates) {
  const result=[]; for (const page of pages) { const source = page?.values || candidates.map((k)=>page?.[k]).find(Array.isArray) || []; result.push(...source); }
  const seen = new Set(); return result.filter((v)=>{ const key=v?.id || JSON.stringify(v); if(seen.has(key)) return false; seen.add(key); return true; });
}
function cleanDescription(text) {
  return String(text || '')
    .replace(/\bSubtareas\b[\s\S]*$/i, '')
    .replace(/\bActividades vinculadas\b[\s\S]*$/i, '')
    .replace(/\bAñadir subtarea\b/gi, '')
    .replace(/\bAñadir actividad vinculada\b/gi, '')
    .replace(/\s+/g, ' ')
    .trim();
}
return [...byKey.entries()].map(([issueKey, group]) => {
  const seed = group[0].seed || {};
  const issue = group.find((r) => r.recordType === 'issue')?.payload || {};
  const comments = pageItems(group.filter((r)=>r.recordType==='commentsPage').map((r)=>r.payload), ['comments']);
  const worklogs = pageItems(group.filter((r)=>r.recordType==='worklogsPage').map((r)=>r.payload), ['worklogs']);
  const changelog = pageItems(group.filter((r)=>r.recordType==='changelogPage').map((r)=>r.payload), ['histories']);
  const fields = issue.fields || {};
  const links = (fields.issuelinks || []).map((link) => {
    const related = link.outwardIssue || link.inwardIssue; if (!related?.key) return null;
    return { key: String(related.key).toUpperCase(), relation: link.type?.name || null, direction: link.outwardIssue ? 'outward' : 'inward', source: 'issueLink', summary: related.fields?.summary || null };
  }).filter(Boolean);
  const all = { fields, renderedFields: issue.renderedFields || {}, comments, worklogs, changelog };
  const own = String(issueKey).toUpperCase();
  const relatedSisKeys = [...new Set([...links.filter((l)=>/^SIS-\d+$/.test(l.key)).map((l)=>l.key), ...refs(all,'SIS').filter((k)=>k!==own)])];
  const recKeys = [...new Set([...links.filter((l)=>/^REC-\d+$/.test(l.key)).map((l)=>l.key), ...refs(all,'REC')])];
  const compactComments = comments.slice(-Math.max(0,Number(seed.maxStoredIssueComments || 12))).map((c)=>({id:c.id||null, created:c.created||null, author:c.author?.displayName||c.author?.name||null, body: allText(c.renderedBody || c.body).join(' ').replace(/\s+/g,' ').slice(0,Number(seed.maxStoredCommentChars || 1000)) }));
  const description = cleanDescription(allText(issue.renderedFields?.description || fields.description).join(' '));
  const errors=group.filter((r)=>r.payload && !r.payload.fields && (r.payload.error || r.payload.message)).map((r)=>({source:r.recordType,message:r.payload.message||r.payload.error,statusCode:r.payload.statusCode||r.payload.code||null}));
  return { json: {
    kind:'issueRecord', role:seed.role || 'unknown', issueKey:own, context:seed.context || {},
    originCommitShas:seed.originCommitShas || [], relatedFrom:seed.relatedFrom || [],
    issue:{ key:own, browseUrl:`${seed.jiraBaseUrl}/browse/${own}`, fetchStatus:issue.fields?'retrieved':(errors.length?'failedOrMissing':'notRetrieved'),
      normalized:{summary:fields.summary||null, issueType:fields.issuetype?.name||null,status:fields.status?.name||null,resolution:fields.resolution?.name||null,priority:fields.priority?.name||null,assignee:fields.assignee?.displayName||fields.assignee?.name||null,labels:fields.labels||[],components:(fields.components||[]).map((v)=>v.name).filter(Boolean),fixVersions:(fields.fixVersions||[]).map((v)=>v.name).filter(Boolean),description:description.slice(0,Number(seed.maxStoredIssueDescriptionChars || 8000)),descriptionText:description.slice(0,Number(seed.maxStoredIssueDescriptionChars || 8000)),descriptionTruncated:description.length>Number(seed.maxStoredIssueDescriptionChars || 8000)},
      relationships:{linkedIssues:links,relatedSisKeys,recKeys}, evidence:{comments:compactComments,activityScanned:{comments:comments.length,worklogs:worklogs.length,changelog:changelog.length}} }, fetchErrors:errors
  }};
});
